@ARTICLE{10.1007/s12011-025-04754-3,
	author = {Tu M and Chen S and Ma L and Zhang J and Cai G and Wang T and Wang C},
	title = {Nano-ZnO Improves IUGR-Induced Abnormal Fat Deposition in Finishing Pigs by Remodeling the Intestinal Microbiota and Regulating Serum Metabolism.},
	journal = {Biol Trace Elem Res},
	year = {2026},
	abstract = {Intrauterine growth retardation (IUGR) in pigs is closely associated with excessive obesity and lipid metabolic abnormalities during postnatal catch-up growth. Nano zinc oxide (Nano-ZnO) is a novel nanomaterial that has antioxidant properties and can improve abnormal lipid metabolism. This study aimed to investigate the weight-reducing effects and mechanisms of Nano-ZnO in IUGR pigs. Six normal birth weight (NBW) and twelve IUGR male piglets were divided into three groups post-weaning (day 22): NBW and IUGR groups received a basal diet, while the IUGR + Zn group was fed a Nano-ZnO-supplemented diet (600 mg/kg). Nano-ZnO significantly reduced backfat thickness and improved fatty acid composition in IUGR pigs. Mechanistically, Nano-ZnO activated the NRF2 signaling pathway, enhancing antioxidant capacity in adipose tissue by elevating T-SOD and T-AOC activities, upregulating SOD/GCLC/GCLM expression, and suppressing KEAP1 and MDA levels. Concurrently, it promoted lipolysis via the adiponectin/AMPK/SREBP1C/PPARγ axis, increasing ACC/CPT-1/HSL activity and mRNA expression while inhibiting FAS. Furthermore, Nano-ZnO modulated gut microbiota composition (e.g., increasing cecal UCG-005, Rikenellaceae RC9, and fecal Phascolarctobacterium) and serum metabolites (e.g., reducing phenylpyruvic acid and 9(10)-EpOME, elevating docosahexaenoic acid and glycochenodeoxycholic acid). These findings demonstrate that Nano-ZnO ameliorates abnormal fat deposition in IUGR pigs through coordinated antioxidant, lipolytic, gut microbial, and metabolic reprogramming.},
	doi = {10.1007/s12011-025-04754-3},
	pmid = {40728547 [Indexed for MEDLINE]}
}

@ARTICLE{10.1210/clinem/dgaf382,
	author = {London A and Schaufuss A, Považan M and Dichman ML and Merhout J and Dirksen C and Madsbad S and Siebner HR and Lundsgaard A and Fritzen AM and Kiens B, Bojsen-Møller KN},
	title = {Effects of Acute Iso- and Hypocaloric Carbohydrate Restriction on Liver Fat and Glucose and Lipid Metabolism.},
	journal = {J Clin Endocrinol Metab},
	year = {2026},
	abstract = {CONTEXT: Liver fat is reduced within days after a low-carbohydrate diet substituted with fat to maintain isocaloric conditions. OBJECTIVE: Investigate the effect of matched carbohydrate restriction during isocaloric and hypocaloric conditions on liver fat and postprandial glucose and lipid metabolism. METHODS: Crossover randomized clinical trial at a research unit. Participants included 15 people with overweight/obesity (body mass index [BMI] 32.5 [31-34] kg/m2, median [IQR]). There were 3 dietary interventions: (1) 2 days of isocaloric control diet (CON), (2) 2 days of CON followed by 2 days of carbohydrate restriction (∼60 g/day) during very-low-calorie conditions (VLCDs), and (3) 2 days of CON followed by 2 days of isocaloric conditions with low carbohydrate (∼60 g/day), high-fat (LCHF) diet. Liver fat was measured using 1H-magnetic resonance spectroscopy. RESULTS: Liver fat was -16% (-34; 4) (median [IQR]) after LCHF relative to after CON (P = .020), but did not differ between VLCD and CON. Fasting plasma concentrations of triacylglycerol, glucose, and insulin were lower after both LCHF and VLCD than after CON. However, postprandial plasma glucose concentrations were higher and insulinogenic index lower after both LCHF and VLCD. CONCLUSION: Two days of LCHF led to lower liver fat, which was not observed after VLCD. This demonstrates the dynamic regulation of liver fat and the beneficial role of substituting carbohydrates with fat to maintain energy provision. Both LCHF and VLCD had positive effects on fasting parameters for glucose metabolism; however, both diets impaired early β-cell response resulting in deterioration in glucose handling during the meal test.},
	doi = {10.1210/clinem/dgaf382},
	pmid = {40601817 [Indexed for MEDLINE]},
	note = {PMC12819859}
}

@ARTICLE{10.1016/j.jare.2025.06.041,
	author = {Shi R and Wei J and Ye J and Song X and Yang X and Zhang Y and Liu S and Ren J and Wang D and Zhao Z and Liu Z and Wang Y and Zhao B and Xiao C and Dai X and Ai L and Liu X},
	title = {The novel synbiotic (Lactiplantibacillus plantarum and galacto-oligosaccharides) ameliorates obesity-related metabolic dysfunction: Arginine as a key mediator signaling molecule.},
	abstract = {OBJECTIVE: This study aimed to develop a novel synbiotic composed of Lactiplantibacillus plantarum LLY-606 and galacto-oligosaccharides (GOS) to improve lipid metabolism in obesity. DESIGN: Through genome-wide analysis using COG and CAZy databases, we identified GOS as a specific growth substrate for Lactiplantibacillus plantarum LLY-606. The efficacy of this synbiotic (LP-GOS) was evaluated in both obese individuals and high-fat diet-induced obese mice. RESULTS: LP-GOS supplementation reduced visceral fat and waist circumference in humans and attenuated obesity in mice. It also improved gut microbiota composition and increased serum arginine levels. Metabolomic and microbiota analyses suggested that enhanced arginine production plays a key role. This was further confirmed by arginine synthesis inhibition, antibiotic treatment, and CRISPR-Cas9-mediated knockout of the Ass1 gene in Lactiplantibacillus plantarum LLY-606. These interventions demonstrated that LP-GOS improves lipid metabolism through arginine-mediated activation of the AMPK pathway. CONCLUSIONS: LP-GOS effectively alleviates obesity-associated lipid metabolism disorders by enhancing arginine production and activating the AMPK signaling pathway.},
	doi = {10.1016/j.jare.2025.06.041},
	pmid = {40545235 [Indexed for MEDLINE]},
	note = {PMC12957849}
}

@ARTICLE{10.1007/s12011-025-04711-0,
	author = {Li X and Wang T and Wang W and Wang Z and Wang H and Fan K and Yang B},
	title = {Gene Dynamics in Maternal Nutrition: The Role of Chromium in Mitigating Offspring Obesity.},
	journal = {Biol Trace Elem Res},
	year = {2026},
	abstract = {This study investigates the potential mechanisms by which maternal chromium (Cr) supplementation mitigates offspring obesity through identification of key regulatory genes. Sixteen pregnant C57BL/6 mice were randomly allocated to either control (CON) or chromium-supplemented (CR) dietary groups, with nutritional interventions administered throughout gestation and lactation. Post-weaning, all offspring received CR diets until 32 weeks of age. Comparative analysis revealed significant reductions in adipose tissue mass and 136 differentially expressed genes (DEGs) in CR offspring adipose tissue, identified through GEO2R analysis. Functional enrichment analyses revealed significant involvement of these DEGs in critical metabolic pathways: lipid metabolism regulation (PPAR signaling), steroid hormone biosynthesis, cholesterol homeostasis, and fatty acid oxidation processes. Protein-protein interaction network analysis identified 14 hub genes central to adipocyte regulation, including ACSL1, DGAT1, ADIPOQ, PPARD, PPARG, SREBF1, APOC2, and FABP1, which collectively demonstrate synergistic effects in suppressing lipid accumulation. These findings elucidate molecular mechanisms underlying chromium-mediated protection against metabolic disorders and propose novel therapeutic targets for intergenerational obesity prevention. The identified gene network provides a framework for developing maternal nutritional strategies and pharmacological interventions targeting epigenetic regulation of lipid metabolism.},
	doi = {10.1007/s12011-025-04711-0},
	pmid = {40536644 [Indexed for MEDLINE]}
}
